func TestBuildContactBodyIncludesLists(t *testing.T) {
	body := buildContactBody("reader@example.com", "Jane", "Doe", []int{123, 456})
	if body["email"] != "reader@example.com" || body["first_name"] != "Jane" || body["last_name"] != "Doe" {
		t.Fatalf("unexpected body fields: %#v", body)
	}
	lists, ok := body["lists"].([]int)
	if !ok || len(lists) != 2 || lists[0] != 123 || lists[1] != 456 {
		t.Fatalf("lists = %#v, want [123 456]", body["lists"])
	}
}

