func TestAudienceMapCountsObservedMembership(t *testing.T) {
	lists := []map[string]any{{"id": float64(1), "name": "A"}, {"id": float64(2), "name": "B"}}
	contacts := []map[string]any{{"lists": []any{float64(2), float64(1)}}, {"lists": []any{float64(2)}}}
	ranked := rankListsByObservedMembership(lists, contacts, 10)
	if got := ranked[0]["id"]; got != 2 {
		t.Fatalf("top list id = %#v, want 2; ranked=%#v", got, ranked)
	}
	if got := ranked[0]["observed_contacts"]; got != 2 {
		t.Fatalf("top observed_contacts = %#v, want 2", got)
	}
}
